const tasks = $('Execute a SQL query').all();
const reminders = $('Execute a SQL query1').all();
const weather = $('HTTP Request').first().json.data.trim();
const calEvents = $('GetTodayEvents').all();

const today = new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long' });

const formatDate = (dateStr) => {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  return d.toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });
};

const formatTime = (dateStr) => {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  return d.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });
};

let message = `Good morning! \nBriefing for ${today}.\n\n`;
message += `${weather}\n`;

// Calendar events
const validEvents = calEvents.filter(e => e.json && e.json.summary);
if (validEvents.length > 0) {
  message += `\nCalendar:\n`;
  validEvents.forEach(e => {
    const ev = e.json;
    let timeStr = '';
    if (ev.start?.dateTime) {
      timeStr = ` — ${formatTime(ev.start.dateTime)}`;
      if (ev.end?.dateTime) timeStr += `–${formatTime(ev.end.dateTime)}`;
    } else if (ev.start?.date) {
      timeStr = ' — All day';
    }
    const loc = ev.location ? ` @ ${ev.location}` : '';
    message += `${ev.summary}${timeStr}${loc}\n`;
  });
}

// Tasks
const validTasks = tasks.filter(t => t.json.title);
if (validTasks.length > 0) {
  message += `\nTasks:\n`;
  validTasks.forEach(t => {
    const due = t.json.due_date ? ` — due ${formatDate(t.json.due_date)}` : '';
    message += `${t.json.title} [${t.json.priority}]${due}\n`;
  });
}

// Reminders
const validReminders = reminders.filter(r => r.json.remind_at && (r.json.message || r.json.task_title));
if (validReminders.length > 0) {
  message += `\nReminders:\n`;
  validReminders.forEach(r => {
    const time = formatTime(r.json.remind_at);
    const msg = r.json.message || r.json.task_title;
    message += `${time}: ${msg}\n`;
  });
}

return [{ json: { message } }];
